<!doctype html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Certificado verificado · AulaPro</title><style>*{box-sizing:border-box}body{margin:0;min-height:100vh;display:grid;place-items:center;padding:24px;background:radial-gradient(circle at top,#dbeafe,#f8fafc 48%);font-family:Inter,system-ui;color:#172554}.card{width:min(720px,100%);background:#fff;border:1px solid #dbe5f1;border-radius:28px;padding:44px;box-shadow:0 30px 80px #1e3a8a24}.check{width:64px;height:64px;border-radius:50%;display:grid;place-items:center;background:#dcfce7;color:#15803d;font-size:32px;font-weight:900}h1{font-size:36px;letter-spacing:-1.4px;margin:24px 0 8px}.lead{color:#64748b;font-size:17px}.certificate{margin-top:30px;padding:26px;border-radius:18px;background:#f8fafc;border:1px solid #e2e8f0;display:grid;grid-template-columns:1fr 1fr;gap:22px}.label{font-size:12px;text-transform:uppercase;letter-spacing:.08em;color:#94a3b8;font-weight:800}.value{font-size:17px;font-weight:750;margin-top:6px}.code{grid-column:1/-1;color:#2563eb}.brand{margin-top:28px;font-weight:850}.brand span{color:#2563eb}@media(max-width:600px){.card{padding:28px}.certificate{grid-template-columns:1fr}.code{grid-column:auto}}</style></head><body><main class="card"><div class="check">✓</div><h1>Certificado auténtico</h1><p class="lead">AulaPro confirma que este logro fue emitido por la plataforma.</p><section class="certificate"><div><div class="label">Estudiante</div><div class="value">{{ $certificate->student->name }}</div></div><div><div class="label">Curso</div><div class="value">{{ $certificate->course->title }}</div></div><div><div class="label">Fecha de emisión</div><div class="value">{{ $certificate->issued_at->translatedFormat('d \d\e F \d\e Y') }}</div></div><div><div class="label">Estado</div><div class="value" style="color:#15803d">Válido</div></div><div class="code"><div class="label">Código único</div><div class="value">{{ $certificate->certificate_code }}</div></div></section><div class="brand">Aula<span>Pro</span></div></main></body></html>
